import{_ as n,C as r,o,c as s,a2 as t,b as l,w as a,a as c,E as d,a3 as u}from"./chunks/framework.B72_uj9U.js";const v=JSON.parse('{"title":"Droid — Agentic Loop","description":"","frontmatter":{},"headers":[],"relativePath":"research/agents/droid/agentic-loop.md","filePath":"research/agents/droid/agentic-loop.md"}'),p={name:"research/agents/droid/agentic-loop.md"};function g(m,e,h,f,b,k){const i=r("Mermaid");return o(),s("div",null,[e[1]||(e[1]=t('<h1 id="droid-—-agentic-loop" tabindex="-1">Droid — Agentic Loop <a class="header-anchor" href="#droid-—-agentic-loop" aria-label="Permalink to &quot;Droid — Agentic Loop&quot;">​</a></h1><blockquote><p>How Droid executes tasks: from delegation to completion, across synchronous and asynchronous modes, with autonomous tool use and human checkpoints.</p></blockquote><h2 id="core-loop-pattern" tabindex="-1">Core Loop Pattern <a class="header-anchor" href="#core-loop-pattern" aria-label="Permalink to &quot;Core Loop Pattern&quot;">​</a></h2><p>Droid&#39;s agentic loop follows a <strong>delegation-oriented</strong> pattern rather than a simple prompt-response cycle. The fundamental model is:</p><ol><li><strong>Task Intake</strong> — Developer delegates a task via any interface (CLI prompt, Slack message, Linear ticket, CI trigger, web workspace).</li><li><strong>Context Assembly</strong> — Droid gathers relevant context: codebase structure, file contents, project management context, previous session history (via compaction).</li><li><strong>Planning</strong> — For complex tasks, Droid enters Specification Mode to generate a detailed implementation plan before executing.</li><li><strong>Autonomous Execution</strong> — Droid executes a series of tool calls (Read, Edit, Execute, Grep, Glob) with minimal human intervention.</li><li><strong>Output Delivery</strong> — Results surface wherever is appropriate: PR created, Slack message sent, CI status updated, IDE diff shown.</li><li><strong>Human Review</strong> — Developer reviews, provides feedback, or approves.</li></ol><h2 id="autonomy-ratio" tabindex="-1">Autonomy Ratio <a class="header-anchor" href="#autonomy-ratio" aria-label="Permalink to &quot;Autonomy Ratio&quot;">​</a></h2><p>Factory Analytics tracks the <strong>autonomy ratio</strong> — the number of tool calls per user message — as a key metric of Droid&#39;s independent execution capability.</p><ul><li>An autonomy ratio of <strong>13x</strong> means Droid performs 13 tool calls for every human message.</li><li>Higher ratios indicate the developer is delegating larger units of work with less hand-holding.</li><li>Enterprise teams track this metric to measure how effectively developers trust and use autonomous agents.</li></ul><p>This metric is fundamentally different from what most coding agents track. Rather than measuring &quot;how good is the AI at coding,&quot; it measures <strong>how much work is delegated per human interaction</strong> — a proxy for real-world productivity impact.</p><h2 id="execution-modes" tabindex="-1">Execution Modes <a class="header-anchor" href="#execution-modes" aria-label="Permalink to &quot;Execution Modes&quot;">​</a></h2><h3 id="interactive-mode-cli-ide-web" tabindex="-1">Interactive Mode (CLI, IDE, Web) <a class="header-anchor" href="#interactive-mode-cli-ide-web" aria-label="Permalink to &quot;Interactive Mode (CLI, IDE, Web)&quot;">​</a></h3><p>In interactive mode, Droid operates as a conversational agent:</p>',12)),(o(),l(u,null,{default:a(()=>[d(i,{id:"mermaid-81",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20A%5B%22Developer%20delegates%20task%22%5D%20--%3E%20B%5B%22Context%20Assembly%20(compaction-aware)%3Cbr%2F%3EReads%20relevant%20files%2C%20session%20history%22%5D%0A%20%20%20%20B%20--%3E%20C%5B%22Planning%3Cbr%2F%3EMay%20enter%20Specification%20Mode%20for%20complex%20tasks%22%5D%0A%20%20%20%20C%20--%3E%20D%5B%22Execute%20tool%20call%3Cbr%2F%3ERead%20files%20%C2%B7%20Grep%20%C2%B7%20Edit%20files%20%C2%B7%20Execute%20tests%22%5D%0A%20%20%20%20D%20--%3E%20E%7BMore%20tools%20needed%3F%7D%0A%20%20%20%20E%20--%20yes%20--%3E%20D%0A%20%20%20%20E%20--%20no%20--%3E%20F%5B%22Present%20Results%3Cbr%2F%3EDiff%2C%20PR%2C%20summary%22%5D%0A%20%20%20%20F%20--%3E%20G%5B%22Await%20Feedback%3Cbr%2F%3EHuman%20reviews%2C%20iterates%2C%20or%20approves%22%5D%0A"})]),fallback:a(()=>[...e[0]||(e[0]=[c(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=t('<h3 id="non-interactive-mode-ci-cd" tabindex="-1">Non-Interactive Mode (CI/CD) <a class="header-anchor" href="#non-interactive-mode-ci-cd" aria-label="Permalink to &quot;Non-Interactive Mode (CI/CD)&quot;">​</a></h3><p>In CI/CD pipelines, Droid operates autonomously without human interaction:</p><ul><li>Triggered by events (PR opened, CI failure, scheduled job).</li><li>Executes predefined workflows (auto-review, GitHub Actions repair).</li><li>Produces artifacts (review comments, fix PRs, status updates).</li><li>Controlled by <code>.droid.yaml</code> configuration.</li></ul><h3 id="async-delegation-mode-slack-linear-teams" tabindex="-1">Async Delegation Mode (Slack, Linear, Teams) <a class="header-anchor" href="#async-delegation-mode-slack-linear-teams" aria-label="Permalink to &quot;Async Delegation Mode (Slack, Linear, Teams)&quot;">​</a></h3><p>When tasks are delegated from messaging/PM tools:</p><ul><li>Developer sends a natural language task (&quot;Fix the flaky test in <code>auth_test.py</code>&quot;).</li><li>Droid acknowledges, begins background execution.</li><li>Progress updates can be monitored across any interface.</li><li>Results are delivered as PRs or status updates.</li></ul><h2 id="auto-review-loop" tabindex="-1">Auto-Review Loop <a class="header-anchor" href="#auto-review-loop" aria-label="Permalink to &quot;Auto-Review Loop&quot;">​</a></h2><p>One of Droid&#39;s most mature agentic loops is automated code review:</p><ol><li><strong>Trigger</strong>: PR is opened (if <code>auto_review.enabled: true</code> in <code>.droid.yaml</code>).</li><li><strong>Filter</strong>: Check skip conditions (draft PRs, bot PRs, WIP titles, excluded labels/branches).</li><li><strong>Analysis</strong>: Read the diff, apply path-specific guidelines, analyze changed files.</li><li><strong>Review</strong>: Generate PR summary, file summaries, actionable review comments, and tips.</li><li><strong>CI Repair</strong>: If GitHub Actions failed, analyze the failure and suggest fixes (<code>github_action_repair: true</code>).</li><li><strong>Skip Transparency</strong>: If review is skipped, optionally leave a comment explaining why.</li></ol><h2 id="specification-mode" tabindex="-1">Specification Mode <a class="header-anchor" href="#specification-mode" aria-label="Permalink to &quot;Specification Mode&quot;">​</a></h2><p>For complex tasks, Droid supports a <strong>Specification Mode</strong> that separates planning from execution:</p><ul><li>A reasoning model (e.g., Claude Opus, o3) generates a detailed implementation specification.</li><li>The spec includes technical details, file changes needed, edge cases, and test requirements.</li><li>An execution model (potentially a different, more cost-efficient model) then implements the spec.</li><li>This mirrors the architect/editor pattern seen in other agents but is built into the platform with explicit model routing.</li></ul><h2 id="session-continuity" tabindex="-1">Session Continuity <a class="header-anchor" href="#session-continuity" aria-label="Permalink to &quot;Session Continuity&quot;">​</a></h2><p>Unlike most agents where each conversation is ephemeral, Droid sessions can persist across:</p><ul><li><strong>Days or weeks</strong>: The compaction engine preserves critical context across extremely long sessions.</li><li><strong>Interface transitions</strong>: Start in Slack, continue in CLI, review in web.</li><li><strong>Teaching and reuse</strong>: Developers can teach Droid a pattern once, and it applies the pattern independently across subsequent iterations (as demonstrated by Chainguard&#39;s package-building workflow).</li></ul><h2 id="cloud-local-background-agents" tabindex="-1">Cloud &amp; Local Background Agents <a class="header-anchor" href="#cloud-local-background-agents" aria-label="Permalink to &quot;Cloud &amp; Local Background Agents&quot;">​</a></h2><p>Factory supports both cloud and local background agents:</p><ul><li><strong>Cloud background agents</strong>: Execute in Factory&#39;s infrastructure, accessible from web/Slack.</li><li><strong>Local background agents</strong>: Execute on the developer&#39;s machine via CLI.</li><li>Both modes support long-running tasks that don&#39;t require constant developer attention.</li></ul>',18))])}const x=n(p,[["render",g]]);export{v as __pageData,x as default};
